// src/components/employees/EmployeeList.jsx
import React, { useState, useEffect } from 'react';
import { PlusIcon, PencilIcon, TrashIcon } from '@heroicons/react/24/outline';
import { employeeService } from '../../services/employeeService';

const EmployeeList = ({ onAddEmployee, onEditEmployee }) => {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    department: '',
    status: '',
    search: ''
  });

  useEffect(() => {
    fetchEmployees();
  }, [filters]);

  const fetchEmployees = async () => {
    try {
      setLoading(true);
      const response = await employeeService.getEmployees(filters);
      setEmployees(response.data);
    } catch (error) {
      console.error('직원 목록 조회 실패:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteEmployee = async (employeeId) => {
    if (window.confirm('정말로 이 직원을 삭제하시겠습니까?')) {
      try {
        await employeeService.deleteEmployee(employeeId);
        fetchEmployees(); // 목록 새로고침
      } catch (error) {
        console.error('직원 삭제 실패:', error);
        alert('직원 삭제에 실패했습니다.');
      }
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="bg-white shadow-sm rounded-lg">
      {/* 헤더 및 필터 */}
