# tests/test_employee_api.py
import pytest
from fastapi.testclient import TestClient
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker
from app.main import app
from app.db.database import get_db, Base

# 테스트용 데이터베이스 설정
SQLALCHEMY_DATABASE_URL = "sqlite:///./test.db"
engine = create_engine(SQLALCHEMY_DATABASE_URL, connect_args={"check_same_thread": False})
TestingSessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

Base.metadata.create_all(bind=engine)

def override_get_db():
    try:
        db = TestingSessionLocal()
        yield db
    finally:
        db.close()

app.dependency_overrides[get_db] = override_get_db
client = TestClient(app)

class TestEmployeeAPI:
    def test_create_employee(self):
        employee_data = {
            "employee_number": "TEST001",
            "name": "테스트 직원",
            "email": "test@company.com",
            "department": "개발팀",
            "position": "사원",
            "hire_date": "2024-01-01",
            "salary": 3000000
        }

        response = client.post("/api/v1/employees/", json=employee_data)
        assert response.status_code == 200

        data = response.json()
        assert data["name"] == "테스트 직원"
        assert data["email"] == "test@company.com"

    def test_get_employees(self):
        response = client.get("/api/v1/employees/")
        assert response.status_code == 200

        data = response.json()
        assert isinstance(data, list)

    def test_get_employee_by_id(self):
        # 먼저 직원 생성
        employee_data = {
            "employee_number": "TEST002",
            "name": "테스트 직원2",
            "email": "test2@company.com",
            "department": "영업팀",
            "position": "대리",
            "hire_date": "2024-01-01",
            "salary": 3500000
        }

        create_response = client.post("/api/v1/employees/", json=employee_data)
        employee_id = create_response.json()["id"]

        # 조회 테스트
        response = client.get(f"/api/v1/employees/{employee_id}")
        assert response.status_code == 200

        data = response.json()
        assert data["name"] == "테스트 직원2"

    def test_update_employee(self):
        # 직원 생성
        employee_data = {
            "employee_number": "TEST003",
            "name": "테스트 직원3",
            "email": "test3@company.com",
            "department": "개발팀",
            "position": "사원",
            "hire_date": "2024-01-01",
            "salary": 3000000
        }

        create_response = client.post("/api/v1/employees/", json=employee_data)
        employee_id = create_response.json()["id"]

        # 수정 데이터
        update_data = {
            "position": "대리",
            "salary": 3500000
        }

        response = client.put(f"/api/v1/employees/{employee_id}", json=update_data)
        assert response.status_code == 200

        data = response.json()
        assert data["position"] == "대리"
        assert data["salary"] == 3500000

    def test_delete_employee(self):
        # 직원 생성
        employee_data = {
            "employee_number": "TEST004",
            "name": "테스트 직원4",
            "email": "test4@company.com",
            "department": "개발팀",
            "position": "사원",
            "hire_date": "2024-01-01",
            "salary": 3000000
        }

        create_response = client.post("/api/v1/employees/", json=employee_data)
        employee_id = create_response.json()["id"]

        # 삭제 테스트
        response = client.delete(f"/api/v1/employees/{employee_id}")
        assert response.status_code == 200

        # 삭제 확인
        get_response = client.get(f"/api/v1/employees/{employee_id}")
        assert get_response.status_code == 404

# 테스트 실행
if __name__ == "__main__":
    pytest.main([__file__])
