import requests
import json
from app.core.config import settings

class SlackNotifier:
    def __init__(self, webhook_url: str):
        self.webhook_url = webhook_url

    def send_error_alert(self, error_message: str, context: dict = None):
        """에러 발생 시 Slack 알림"""
        payload = {
            "text": "🚨 HR SaaS 에러 발생",
            "attachments": [
                {
                    "color": "danger",
                    "fields": [
                        {
                            "title": "에러 메시지",
                            "value": error_message,
                            "short": False
                        },
                        {
                            "title": "발생 시간",
                            "value": str(datetime.now()),
                            "short": True
                        }
                    ]
                }
            ]
        }

        if context:
            for key, value in context.items():
                payload["attachments"][0]["fields"].append({
                    "title": key,
                    "value": str(value),
                    "short": True
                })

        requests.post(self.webhook_url, json=payload)

    def send_success_alert(self, message: str):
        """성공 알림"""
        payload = {
            "text": f"✅ {message}",
            "attachments": [
                {
                    "color": "good",
                    "text": f"시간: {datetime.now()}"
                }
            ]
        }
        requests.post(self.webhook_url, json=payload)

# 사용 예시
notifier = SlackNotifier(settings.slack_webhook_url)

@app.middleware("http")
async def error_handler(request: Request, call_next):
    try:
        response = await call_next(request)
        return response
    except Exception as e:
        notifier.send_error_alert(
            str(e),
            context={
                "URL": str(request.url),
                "Method": request.method,
                "User": getattr(request.state, 'user_id', 'Anonymous')
            }
        )
        raise
